import { useEffect, useMemo, useState } from "react";
import api from "../api";
import { useAuth } from "../AuthContext";

const PAGE_SIZE = 10;
const VND = (v) => (Number(v || 0)).toLocaleString("vi-VN") + " ₫";

// UI ↔ enum backend
const METHOD_OPTS = [
    { label: "Chuyển khoản", value: "BANK_TRANSFER" },
    { label: "Tiền mặt", value: "CASH" },
];
const STATUS_OPTS = [
    { label: "Chờ xác nhận", value: "PENDING" },
    { label: "Đã thanh toán", value: "PAID" },
];
const toLabel = (opts, v) =>
    opts.find((o) => o.value === v || o.label === v)?.label || v || "";
const toValue = (opts, l) =>
    opts.find((o) => o.label === l || o.value === l)?.value || l;

// chuẩn hoá danh sách từ backend (pageable/array)
function normalizeList(d) {
    return Array.isArray(d)
        ? { list: d, pages: 1 }
        : { list: d?.content || [], pages: d?.totalPages || 1 };
}

// đoán quyền từ nhiều kiểu schema
function hasAnyRole(user, allow = []) {
    if (!user) return false;
    const S = new Set();
    const add = (x) => {
        if (!x) return;
        if (Array.isArray(x)) return x.forEach(add);
        if (typeof x === "string") return S.add(x.toUpperCase());
        if (typeof x === "object") ["role", "name", "authority"].map((k) => x[k]).forEach(add);
    };
    add(user?.role);
    add(user?.roles);
    add(user?.authorities);
    if (S.size === 0) return true; // không rõ schema -> không ẩn nút
    return allow.some((r) => S.has(r));
}

// helpers tiền / ngày
const fmtMoneyInline = (n) =>
    (Number(n || 0)).toLocaleString("vi-VN", { maximumFractionDigits: 0 });
const parseMoney = (s) => {
    if (typeof s === "number") return s;
    const digits = String(s || "").replace(/[^\d]/g, "");
    return Number(digits || 0);
};
const toISO = (d) => {
    if (!d) return "";
    if (/^\d{4}-\d{2}-\d{2}$/.test(d)) return d;
    const m = String(d).match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
    if (m) return `${m[3]}-${m[2]}-${m[1]}`;
    try { const dt = new Date(d); if (!isNaN(dt)) return dt.toISOString().slice(0, 10); } catch {}
    return "";
};

export default function Payments() {
    const { user } = useAuth();
    const canEdit = hasAnyRole(user, ["ADMIN", "ACCOUNTANT"]);

    const [rows, setRows] = useState([]);
    const [page, setPage] = useState(0);
    const [totalPages, setTotalPages] = useState(1);
    const [loading, setLoading] = useState(true);

    const [contracts, setContracts] = useState([]);
    const [currentContractId, setCurrentContractId] = useState(""); // bắt buộc chọn HĐ

    const [showModal, setShowModal] = useState(false);
    const [editing, setEditing] = useState(null);

    const [form, setForm] = useState({
        contractId: "",
        date: "",
        amount: "",
        method: "Chuyển khoản",
        confirmer: "",
        status: "Chờ xác nhận",
    });

    // map id -> contract để tra nhanh
    const contractMap = useMemo(() => {
        const m = new Map();
        for (const c of contracts) m.set(c.id, c);
        return m;
    }, [contracts]);

    const selectedContract = contractMap.get(Number(currentContractId));
    const remainBefore =
        (selectedContract?.remainingAmount ??
            (selectedContract
                ? Number(selectedContract.totalAmount || 0) - Number(selectedContract.paidAmount || 0)
                : 0)) || 0;
    const amountNum = parseMoney(form.amount);
    const remainAfter = remainBefore - amountNum;

    const selectedContractDisplay = useMemo(() => {
        const ct = selectedContract;
        if (!ct) return "";
        const code = ct.contractCode || ct.code || `HD-${ct.id}`;
        const cus = ct.customer?.name || ct.customerName || "";
        return `${code} - ${cus}`;
    }, [selectedContract]);

    /** Load contracts */
    useEffect(() => {
        (async () => {
            try {
                const { data } = await api.get("/api/contracts", {
                    params: { page: 0, size: 1000, sort: "id,desc" },
                });
                const content = Array.isArray(data) ? data : data?.content || [];
                setContracts(content);

                // ưu tiên contractId trên URL (?contractId=) nếu có
                const urlId = new URLSearchParams(window.location.search).get("contractId");
                const firstId = urlId && content.some((c) => String(c.id) === String(urlId))
                    ? urlId
                    : content[0]?.id || "";
                setCurrentContractId(String(firstId || ""));
            } catch (e) {
                console.error("Load contracts failed:", e);
            }
        })();
    }, []);

    /** Load payments theo HĐ */
    useEffect(() => {
        setPage(0); // đổi HĐ thì về trang đầu
    }, [currentContractId]);

    useEffect(() => {
        load();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [page, currentContractId]);

    async function load() {
        if (!currentContractId) { setRows([]); setTotalPages(1); return; }
        setLoading(true);
        try {
            const params = { page, size: PAGE_SIZE, sort: "id,desc", contractId: currentContractId };
            let data;
            try {
                // ưu tiên filter server-side nếu có
                ({ data } = await api.get("/api/payments", { params }));
            } catch {
                // fallback: lấy tất cả rồi lọc client-side
                ({ data } = await api.get("/api/payments", { params: { page, size: PAGE_SIZE, sort: "id,desc" } }));
            }
            const { list, pages } = normalizeList(data);
            const filtered = list.filter((r) => String(r.contractId || r.contract?.id) === String(currentContractId));
            setRows(filtered);
            setTotalPages(pages);
        } catch (e) {
            console.error(e);
            setRows([]);
            setTotalPages(1);
        } finally {
            setLoading(false);
        }
    }

    /** Modal open/close */
    function openCreate() {
        if (!currentContractId) { alert("Vui lòng chọn hợp đồng trước khi thêm thanh toán."); return; }
        setEditing(null);
        setForm({
            contractId: currentContractId,
            date: new Date().toISOString().slice(0, 10),
            amount: "",
            method: "Chuyển khoản",
            confirmer: "",
            status: "Chờ xác nhận",
        });
        setShowModal(true);
    }

    function openEdit(p) {
        setEditing(p);
        setForm({
            contractId: String(p.contractId || p.contract?.id || currentContractId),
            date: p.paymentDate || p.date || "",
            amount: fmtMoneyInline(p.amount ?? p.money ?? 0),
            method: toLabel(METHOD_OPTS, p.paymentMethod || p.method || "BANK_TRANSFER"),
            confirmer: p.confirmedBy || p.confirmer || "",
            status: toLabel(STATUS_OPTS, p.status || p.paymentStatus || "PENDING"),
        });
        setShowModal(true);
    }

    /** Save */
    async function save(e) {
        e.preventDefault();

        const contractIdNum = Number(form.contractId);
        const amount = parseMoney(form.amount);
        const dateISO = toISO(form.date);
        if (!contractIdNum) return alert("Vui lòng chọn hợp đồng.");
        if (!dateISO)       return alert("Vui lòng chọn ngày thanh toán.");
        if (amount <= 0)    return alert("Số tiền phải lớn hơn 0.");

        if (selectedContract && remainAfter < 0) {
            const ok = window.confirm(
                `Số tiền vượt quá số còn lại của hợp đồng (${VND(remainBefore)}). Bạn vẫn muốn lưu?`
            );
            if (!ok) return;
        }

        const payload = {
            contractId: contractIdNum,
            contract: { id: contractIdNum },

            amount,

            paymentDate: dateISO,
            date: dateISO, // alias

            paymentMethod: toValue(METHOD_OPTS, form.method),
            method: toValue(METHOD_OPTS, form.method), // alias

            confirmedBy: form.confirmer?.trim() || null,
            confirmer: form.confirmer?.trim() || null, // alias

            status: toValue(STATUS_OPTS, form.status),
            paymentStatus: toValue(STATUS_OPTS, form.status), // alias
        };

        try {
            if (editing) await api.put(`/api/payments/${editing.id}`, payload);
            else         await api.post("/api/payments", payload);

            setShowModal(false);
            await load();
            // refresh số liệu HĐ (đã thu/còn lại)
            try {
                const { data } = await api.get("/api/contracts", { params: { page: 0, size: 1000, sort: "id,desc" } });
                const content = Array.isArray(data) ? data : data?.content || [];
                setContracts(content);
            } catch {}
        } catch (err) {
            const data = err?.response?.data;
            let msg =
                (typeof data === "string" && data) ||
                data?.message || data?.error ||
                `HTTP ${err?.response?.status || ""}`;
            try { if (!msg && data) msg = JSON.stringify(data); } catch {}
            alert(msg || "Lưu thanh toán thất bại");
            console.error("Save payment error:", err?.response || err, "\nPayload:", payload);
        }
    }

    async function removeRow(row) {
        if (!window.confirm("Xoá đợt thanh toán này?")) return;
        try { await api.delete(`/api/payments/${row.id}`); await load(); }
        catch (err) {
            console.error(err);
            alert(err?.response?.data?.message || "Xoá thanh toán thất bại");
        }
    }

    /** UI */
    return (
        <div className="space-y-4">
            <div className="flex items-center justify-between gap-3 flex-wrap">
                <div>
                    <h2 className="text-lg font-semibold">Thanh toán</h2>
                    <p className="text-sm text-slate-500">Quản lý các đợt thanh toán theo hợp đồng</p>
                </div>

                <div className="flex items-center gap-2">
                    {/* BẮT BUỘC CHỌN HỢP ĐỒNG – không có option “Tất cả hợp đồng” */}
                    <select
                        value={currentContractId}
                        onChange={(e) => setCurrentContractId(e.target.value)}
                        className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow text-sm"
                        title="Chọn hợp đồng"
                    >
                        {contracts.length === 0 && <option value="">— Chưa có hợp đồng —</option>}
                        {contracts.map((ct) => {
                            const code = ct.contractCode || ct.code || `HD-${ct.id}`;
                            const cus = ct.customer?.name || ct.customerName || "";
                            return (
                                <option key={ct.id} value={ct.id}>
                                    {code} - {cus}
                                </option>
                            );
                        })}
                    </select>

                    {canEdit && (
                        <button
                            onClick={openCreate}
                            className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700"
                        >
                            Thêm đợt thanh toán
                        </button>
                    )}
                </div>
            </div>

            {/* Thông tin tóm tắt HĐ đang chọn */}
            {selectedContract && (
                <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                    <div className="rounded-xl bg-slate-50 p-3">
                        <div className="text-xs text-slate-500">Tổng giá trị</div>
                        <div className="font-semibold">{VND(selectedContract.totalAmount)}</div>
                    </div>
                    <div className="rounded-xl bg-slate-50 p-3">
                        <div className="text-xs text-slate-500">Đã thu</div>
                        <div className="font-semibold">{VND(selectedContract.paidAmount)}</div>
                    </div>
                    <div className="rounded-xl bg-slate-50 p-3">
                        <div className="text-xs text-slate-500">Còn lại</div>
                        <div className="font-semibold">{VND(selectedContract.remainingAmount ?? remainBefore)}</div>
                    </div>
                    <div className="rounded-xl bg-slate-50 p-3">
                        <div className="text-xs text-slate-500">Khách hàng</div>
                        <div className="font-medium">
                            {selectedContract.customer?.name || selectedContract.customerName || "—"}
                        </div>
                    </div>
                </div>
            )}

            <div className="bg-white rounded-2xl border border-indigo-100 shadow overflow-hidden">
                <div className="overflow-auto">
                    <table className="min-w-full text-sm">
                        <thead className="bg-indigo-50 text-slate-600">
                        <tr>
                            <th className="px-4 py-3 text-left">Mã HĐ</th>
                            <th className="px-4 py-3 text-left">Ngày</th>
                            <th className="px-4 py-3 text-left">Số tiền</th>
                            <th className="px-4 py-3 text-left">Phương thức</th>
                            <th className="px-4 py-3 text-left">Trạng thái</th>
                            <th className="px-4 py-3 text-left">Xác nhận</th>
                            <th className="px-4 py-3 text-right">Thao tác</th>
                        </tr>
                        </thead>
                        <tbody className="divide-y">
                        {loading ? (
                            <tr><td className="px-4 py-6" colSpan={7}>Đang tải…</td></tr>
                        ) : rows.length === 0 ? (
                            <tr><td className="px-4 py-6" colSpan={7}>Chưa có dữ liệu</td></tr>
                        ) : (
                            rows.map((p) => {
                                const code =
                                    p.contractCode ||
                                    p.contract?.contractCode ||
                                    p.contract?.code ||
                                    (p.contractId ? "HD-" + p.contractId : "");
                                const mLabel = toLabel(METHOD_OPTS, p.paymentMethod || p.method);
                                const sLabel = toLabel(STATUS_OPTS, p.status || p.paymentStatus);
                                return (
                                    <tr key={p.id} className="hover:bg-indigo-50/40">
                                        <td className="px-4 py-3 font-medium">{code}</td>
                                        <td className="px-4 py-3">{p.paymentDate || p.date}</td>
                                        <td className="px-4 py-3">{VND(p.amount ?? p.money)}</td>
                                        <td className="px-4 py-3">{mLabel || "-"}</td>
                                        <td className="px-4 py-3">
                        <span className={
                            "px-2 py-0.5 rounded-full text-xs " +
                            ((sLabel || "") === "Đã thanh toán"
                                ? "bg-emerald-100 text-emerald-700"
                                : "bg-amber-100 text-amber-700")
                        }>
                          {sLabel || "-"}
                        </span>
                                        </td>
                                        <td className="px-4 py-3">{p.confirmedBy || p.confirmer || "-"}</td>
                                        <td className="px-4 py-3 text-right">
                                            {canEdit ? (
                                                <div className="inline-flex gap-2">
                                                    <button onClick={() => openEdit(p)}
                                                            className="px-2 py-1 rounded bg-indigo-50 text-indigo-700 hover:bg-indigo-100">Sửa</button>
                                                    <button onClick={() => removeRow(p)}
                                                            className="px-2 py-1 rounded bg-rose-50 text-rose-700 hover:bg-rose-100">Xóa</button>
                                                </div>
                                            ) : <span className="text-slate-400">—</span>}
                                        </td>
                                    </tr>
                                );
                            })
                        )}
                        </tbody>
                    </table>
                </div>
            </div>

            <div className="flex gap-2">
                <button className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                        onClick={() => setPage((p) => Math.max(0, p - 1))}
                        disabled={page <= 0}>← Trước</button>
                <div className="px-3 py-1.5 text-sm">Trang {page + 1}/{totalPages}</div>
                <button className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                        onClick={() => setPage((p) => p + 1)}
                        disabled={page + 1 >= totalPages}>Sau →</button>
            </div>

            {/* Modal: luôn gắn vào HĐ đang chọn, ẩn chọn HĐ */}
            {showModal && canEdit && (
                <div className="fixed inset-0 z-40 bg-black/40 grid place-items-center p-4">
                    <div className="w-full max-w-3xl bg-white rounded-2xl shadow-xl border border-indigo-100">
                        <div className="p-5 border-b flex items-center justify-between">
                            <div className="font-semibold">{editing ? "Sửa đợt thanh toán" : "Thêm đợt thanh toán"}</div>
                            <button className="text-slate-500 hover:text-slate-700" onClick={() => setShowModal(false)}>Đóng</button>
                        </div>

                        <form noValidate onSubmit={save} className="p-5 grid grid-cols-1 md:grid-cols-2 gap-4">
                            {/* Hợp đồng đang chọn */}
                            <div className="md:col-span-2">
                                <label className="text-sm text-slate-600">Hợp đồng</label>
                                <input
                                    disabled
                                    value={selectedContractDisplay}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-slate-50 text-slate-600"
                                />
                                {/* Số liệu hợp đồng + sau thu */}
                                {selectedContract && (
                                    <div className="mt-2 grid grid-cols-2 md:grid-cols-4 gap-2 text-xs text-slate-600">
                                        <div className="rounded-lg bg-slate-50 px-3 py-2">
                                            <div>Tổng giá trị</div><div className="font-semibold">{VND(selectedContract.totalAmount)}</div>
                                        </div>
                                        <div className="rounded-lg bg-slate-50 px-3 py-2">
                                            <div>Đã thu</div><div className="font-semibold">{VND(selectedContract.paidAmount)}</div>
                                        </div>
                                        <div className="rounded-lg bg-slate-50 px-3 py-2">
                                            <div>Còn lại</div><div className="font-semibold">{VND(remainBefore)}</div>
                                        </div>
                                        <div className="rounded-lg bg-slate-50 px-3 py-2">
                                            <div>Sau thu</div>
                                            <div className={"font-semibold " + (remainAfter < 0 ? "text-rose-600" : "text-slate-900")}>
                                                {VND(Math.max(0, remainAfter))}{remainAfter < 0 ? " (vượt)" : ""}
                                            </div>
                                        </div>
                                    </div>
                                )}
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Ngày</label>
                                <input required type="date" value={form.date}
                                       onChange={(e) => setForm((f) => ({ ...f, date: e.target.value }))}
                                       className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"/>
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Số tiền (đ)</label>
                                <input
                                    type="text" required inputMode="numeric" autoComplete="off"
                                    value={form.amount}
                                    onChange={(e) => setForm((f) => ({ ...f, amount: fmtMoneyInline(parseMoney(e.target.value)) }))}
                                    placeholder="VD: 200.000.000"
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow tabular-nums"
                                />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Phương thức</label>
                                <select value={form.method}
                                        onChange={(e) => setForm((f) => ({ ...f, method: e.target.value }))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow">
                                    {METHOD_OPTS.map((o) => <option key={o.value} value={o.label}>{o.label}</option>)}
                                </select>
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Người xác nhận</label>
                                <input value={form.confirmer}
                                       onChange={(e) => setForm((f) => ({ ...f, confirmer: e.target.value }))}
                                       className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                       placeholder="VD: Kế toán A"/>
                            </div>

                            <div className="md:col-span-2">
                                <label className="text-sm text-slate-600">Trạng thái</label>
                                <select value={form.status}
                                        onChange={(e) => setForm((f) => ({ ...f, status: e.target.value }))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow">
                                    {STATUS_OPTS.map((o) => <option key={o.value} value={o.label}>{o.label}</option>)}
                                </select>
                            </div>

                            <div className="md:col-span-2 flex items-center justify-end gap-2 pt-2">
                                <button type="button" className="px-3 py-2 rounded-lg bg-slate-100 hover:bg-slate-200"
                                        onClick={() => setShowModal(false)}>Huỷ</button>
                                <button className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">Lưu</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}
